<script setup lang="ts">import{computed,onMounted,ref}from"vue";import{CalendarDays}from"lucide-vue-next";import{api,type Order}from"../api";import PageHeader from"../components/PageHeader.vue";const orders=ref<Order[]>([]),tab=ref("reserved");const groups={reserved:["pending_payment","paid","confirmed"],completed:["completed"],cancelled:["cancelled","refunded","expired"]};const filtered=computed(()=>orders.value.filter(o=>groups[tab.value as keyof typeof groups].includes(o.status)));const status:Record<string,string>={pending_payment:"已预约",paid:"已预约",confirmed:"已预约",completed:"已完成",cancelled:"已取消",refunded:"已取消",expired:"已取消"};onMounted(async()=>orders.value=await api.orders());</script><template><main><PageHeader title="我的预约"/><div class="order-tabs"><button :class="{active:tab==='reserved'}" @click="tab='reserved'">已预约</button><button :class="{active:tab==='completed'}" @click="tab='completed'">已完成</button><button :class="{active:tab==='cancelled'}" @click="tab='cancelled'">已取消</button></div><section class="order-list"><article v-for="o in filtered" :key="o.id" @click="$router.push(`/orders/${o.id}`)"><header><h3>{{o.hospitalName}}</h3><span>{{status[o.status]}}</span></header><dl><dt>就诊科室</dt><dd>{{o.departmentName}}</dd><dt>就诊医生</dt><dd>{{o.doctorName}}　{{o.doctorTitle}}</dd><dt>就诊时间</dt><dd>{{o.visitDate}}　{{o.period}}</dd></dl></article><div v-if="!filtered.length" class="empty"><CalendarDays/><p>暂无{{status[groups[tab as keyof typeof groups][0]]}}记录</p></div></section></main>
</template>
